import React, { useEffect, useMemo, useState } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import Card from './components/Card';
import useFetch from './hooks/useFetch';
import { Idea, Feature, Testimonial } from './types';

const allTaglines = [
  'Ship lovable features faster',
  'Turn feedback into product magic',
  'From ideas to impact — beautifully',
  'Understand users. Prioritize with confidence.',
  'Build what users can’t stop talking about',
  'Make every release feel like a love letter'
];

export default function App() {
  const [dark, setDark] = useState<boolean>(() => {
    const saved = localStorage.getItem('loveable:theme');
    return saved ? saved === 'dark' : false;
  });
  useEffect(() => {
    document.documentElement.classList.toggle('dark', dark);
    localStorage.setItem('loveable:theme', dark ? 'dark' : 'light');
  }, [dark]);

  const [tagline, setTagline] = useState<string>(() => allTaglines[Math.floor(Math.random() * allTaglines.length)]);
  const regenerateTagline = () => {
    let next = allTaglines[Math.floor(Math.random() * allTaglines.length)];
    if (next === tagline) next = allTaglines[(allTaglines.indexOf(tagline) + 1) % allTaglines.length];
    setTagline(next);
  };

  const { data: featuresData } = useFetch<Feature[]>('mock:features');
  const { data: testimonialsData } = useFetch<Testimonial[]>('mock:testimonials');
  const { data: ideasData } = useFetch<Idea[]>('mock:ideas');

  const [ideas, setIdeas] = useState<Idea[]>([]);
  const [search, setSearch] = useState('');
  const [activeTag, setActiveTag] = useState<string>('All');
  const [onlySaved, setOnlySaved] = useState<boolean>(false);
  const [sortBy, setSortBy] = useState<'trending' | 'newest'>('trending');

  useEffect(() => {
    const persisted = localStorage.getItem('loveable:ideas');
    if (ideasData) {
      let next = ideasData;
      if (persisted) {
        try {
          const saved: Idea[] = JSON.parse(persisted);
          const map = new Map(saved.map(i => [i.id, i] as const));
          next = ideasData.map(i => map.get(i.id) ?? i);
        } catch {}
      }
      setIdeas(next);
    }
  }, [ideasData]);

  useEffect(() => {
    if (ideas.length) {
      localStorage.setItem('loveable:ideas', JSON.stringify(ideas));
    }
  }, [ideas]);

  const allTags = useMemo(() => {
    const s = new Set<string>();
    ideas.forEach(i => i.tags.forEach(t => s.add(t)));
    return ['All', ...Array.from(s)];
  }, [ideas]);

  const filteredIdeas = useMemo(() => {
    let res = ideas.slice();
    if (activeTag !== 'All') res = res.filter(i => i.tags.includes(activeTag));
    if (search.trim()) {
      const q = search.toLowerCase();
      res = res.filter(i => i.title.toLowerCase().includes(q) || i.description.toLowerCase().includes(q));
    }
    if (onlySaved) res = res.filter(i => i.saved);
    res.sort((a, b) => {
      if (sortBy === 'trending') return b.upvotes - a.upvotes;
      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
    });
    return res;
  }, [ideas, activeTag, search, onlySaved, sortBy]);

  const handleUpvote = (id: string) => {
    setIdeas(prev => prev.map(it => (it.id === id ? { ...it, upvotes: it.upvotes + 1 } : it)));
  };
  const handleSave = (id: string) => {
    setIdeas(prev => prev.map(it => (it.id === id ? { ...it, saved: !it.saved } : it)));
  };

  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newTag, setNewTag] = useState('Idea');
  const addIdea = () => {
    if (!newTitle.trim() || !newDesc.trim()) return;
    const created: Idea = {
      id: 'custom-' + Date.now().toString(36),
      title: newTitle.trim(),
      description: newDesc.trim(),
      image: 'https://images.unsplash.com/photo-1492724441997-5dc865305da7?w=800&q=80&auto=format',
      tags: [newTag.trim() || 'Idea'],
      upvotes: 0,
      saved: true,
      createdAt: new Date().toISOString()
    };
    setIdeas(prev => [created, ...prev]);
    setNewTitle('');
    setNewDesc('');
    setNewTag('Idea');
  };

  const sectionBg = dark ? 'bg-gray-900 text-gray-100' : 'bg-white text-gray-900';
  const subtleBg = dark ? 'bg-gray-800' : 'bg-gray-50';
  const borderColor = dark ? 'border-gray-700' : 'border-gray-200';
  const mutedText = dark ? 'text-gray-300' : 'text-gray-600';

  return (
    <div className={dark ? 'bg-gray-950 text-gray-100 min-h-screen' : 'bg-gray-50 text-gray-900 min-h-screen'}>
      <Header dark={dark} onToggleDark={() => setDark(d => !d)} />

      <main>
        {/* Hero */}
        <section className={`relative ${sectionBg}`}>
          <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(25rem 25rem at 20% 10%, rgba(59,130,246,0.35), transparent), radial-gradient(25rem 25rem at 80% 10%, rgba(16,185,129,0.35), transparent)'}} />
          <div className="max-w-6xl mx-auto px-4 py-20 sm:py-28 relative">
            <div className="grid md:grid-cols-2 gap-10 items-center">
              <div>
                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-blue-100 text-blue-800 text-sm dark:bg-blue-900/40 dark:text-blue-200">
                  <span>❤️ Loveable</span>
                  <span className="opacity-70">– Product Love Platform</span>
                </div>
                <h1 className="mt-6 text-4xl sm:text-5xl font-bold leading-tight">
                  {tagline}
                </h1>
                <p className={`mt-4 ${mutedText} text-lg`}>
                  Collect feedback, prioritize with AI, and ship delightful updates. A playful, modern experience that your team will actually love using.
                </p>
                <div className="mt-6 flex flex-wrap gap-3">
                  <a href="#demo" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-md">Get started free</a>
                  <a href="#pricing" className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition shadow-md dark:bg-gray-700 dark:hover:bg-gray-600">See pricing</a>
                  <button onClick={regenerateTagline} className="px-4 py-2 rounded-lg bg-white text-gray-900 hover:bg-gray-100 transition shadow-md border border-gray-200 dark:bg-gray-800 dark:text-gray-100 dark:hover:bg-gray-700 dark:border-gray-700">Shuffle tagline</button>
                </div>
                <div className={`mt-8 grid grid-cols-3 gap-4 ${mutedText}`}>
                  <div className="p-4 rounded-xl bg-gradient-to-br from-blue-50 to-white dark:from-gray-800 dark:to-gray-900 border ${borderColor}">
                    <div className="text-2xl font-bold text-blue-600">50k+</div>
                    <div className="text-sm">Upvotes tracked</div>
                  </div>
                  <div className="p-4 rounded-xl bg-gradient-to-br from-emerald-50 to-white dark:from-gray-800 dark:to-gray-900 border ${borderColor}">
                    <div className="text-2xl font-bold text-emerald-600">12x</div>
                    <div className="text-sm">Faster decisions</div>
                  </div>
                  <div className="p-4 rounded-xl bg-gradient-to-br from-purple-50 to-white dark:from-gray-800 dark:to-gray-900 border ${borderColor}">
                    <div className="text-2xl font-bold text-purple-600">98%</div>
                    <div className="text-sm">CSAT delight</div>
                  </div>
                </div>
              </div>
              <div className="relative">
                <img
                  alt="Product dashboard"
                  className="w-full rounded-xl shadow-md border object-cover h-80 md:h-[26rem] transition"
                  src="https://images.unsplash.com/photo-1556761175-b413da4baf72?w=1200&q=80&auto=format"
                />
                <div className="absolute -bottom-6 -left-6 bg-white dark:bg-gray-800 rounded-xl shadow-md p-4 flex items-center gap-3 border ${borderColor}">
                  <div className="h-10 w-10 rounded-full bg-gradient-to-tr from-blue-500 to-emerald-500" />
                  <div>
                    <div className="font-semibold">Live Insights</div>
                    <div className={`text-sm ${mutedText}`}>Auto-prioritized by impact</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Demo / Ideas */}
        <section id="demo" className={`${subtleBg} py-16`}>
          <div className="max-w-6xl mx-auto px-4">
            <div className="flex items-center justify-between gap-4 flex-wrap">
              <h2 className="text-2xl font-bold">Roadmap Ideas</h2>
              <div className="flex items-center gap-2">
                <label className={`text-sm ${mutedText}`}>Sort</label>
                <select value={sortBy} onChange={e => setSortBy(e.target.value as any)} className={`px-3 py-2 rounded-lg border ${borderColor} bg-white dark:bg-gray-800`}>
                  <option value="trending">Trending</option>
                  <option value="newest">Newest</option>
                </select>
              </div>
            </div>

            <div className="mt-6 flex flex-wrap items-center gap-3">
              {allTags.map(tag => (
                <button
                  key={tag}
                  onClick={() => setActiveTag(tag)}
                  className={`px-3 py-1.5 rounded-full border text-sm transition ${activeTag === tag ? 'bg-blue-600 text-white border-blue-600' : `bg-white dark:bg-gray-800 ${borderColor} hover:bg-gray-50 dark:hover:bg-gray-700`}`}
                >
                  {tag}
                </button>
              ))}
              <div className="flex-1" />
              <div className="flex items-center gap-2">
                <input
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  placeholder="Search ideas..."
                  className={`px-3 py-2 rounded-lg border ${borderColor} bg-white dark:bg-gray-800 w-56`}
                />
                <button onClick={() => setOnlySaved(s => !s)} className={`px-3 py-2 rounded-lg border ${borderColor} transition ${onlySaved ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700'}`}>
                  {onlySaved ? 'Showing Saved' : 'Show Saved'}
                </button>
              </div>
            </div>

            <div className={`mt-6 p-4 md:p-6 rounded-xl border ${borderColor} ${sectionBg}`}>
              <div className="grid md:grid-cols-3 gap-4">
                <input value={newTitle} onChange={e => setNewTitle(e.target.value)} placeholder="Idea title" className={`px-3 py-2 rounded-lg border ${borderColor} bg-white dark:bg-gray-800`} />
                <input value={newTag} onChange={e => setNewTag(e.target.value)} placeholder="Tag (e.g., Onboarding)" className={`px-3 py-2 rounded-lg border ${borderColor} bg-white dark:bg-gray-800`} />
                <div className="flex gap-2">
                  <input value={newDesc} onChange={e => setNewDesc(e.target.value)} placeholder="Short description" className={`flex-1 px-3 py-2 rounded-lg border ${borderColor} bg-white dark:bg-gray-800`} />
                  <button onClick={addIdea} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add</button>
                </div>
              </div>
            </div>

            <div className="mt-8 grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredIdeas.map(item => (
                <Card
                  key={item.id}
                  id={item.id}
                  title={item.title}
                  description={item.description}
                  image={item.image}
                  tags={item.tags}
                  upvotes={item.upvotes}
                  saved={!!item.saved}
                  onUpvote={() => handleUpvote(item.id)}
                  onSaveToggle={() => handleSave(item.id)}
                />
              ))}
              {filteredIdeas.length === 0 && (
                <div className={`col-span-full text-center p-10 rounded-xl border ${borderColor} ${sectionBg}`}>
                  <div className="text-xl font-semibold">No ideas found</div>
                  <div className={`mt-1 ${mutedText}`}>Try adjusting your filters or add a new idea above.</div>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Features */}
        <section id="features" className={`py-16 ${sectionBg}`}>
          <div className="max-w-6xl mx-auto px-4">
            <div className="flex items-end justify-between gap-4 flex-wrap">
              <div>
                <h2 className="text-2xl font-bold">Why teams love Loveable</h2>
                <p className={`mt-1 ${mutedText}`}>Thoughtfully crafted to help you understand, decide, and ship.</p>
              </div>
              <a href="#pricing" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Start free</a>
            </div>
            <div className="mt-8 grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {(featuresData || []).map(f => (
                <div key={f.id} className={`rounded-xl border ${borderColor} p-6 ${dark ? 'bg-gray-900' : 'bg-white'} shadow-md hover:shadow-lg transition`}>
                  <div className="flex items-center gap-3">
                    <div className="h-11 w-11 rounded-xl bg-gradient-to-tr from-blue-600 to-emerald-500 flex items-center justify-center text-white text-xl">{f.icon}</div>
                    <div className="font-semibold text-lg">{f.title}</div>
                  </div>
                  <p className={`mt-3 ${mutedText}`}>{f.description}</p>
                  <ul className={`mt-4 space-y-2 text-sm ${mutedText}`}>
                    {f.bullets.map((b, idx) => (
                      <li key={idx} className="flex items-start gap-2"><span className="text-emerald-500 mt-0.5">•</span><span>{b}</span></li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Testimonials */}
        <section className={`py-16 ${subtleBg}`}>
          <div className="max-w-6xl mx-auto px-4">
            <h2 className="text-2xl font-bold">What people say</h2>
            <div className="mt-6 grid md:grid-cols-2 lg:grid-cols-3 gap-6">
              {(testimonialsData || []).map(t => (
                <div key={t.id} className={`rounded-xl border ${borderColor} p-6 ${dark ? 'bg-gray-900' : 'bg-white'} shadow-md hover:shadow-lg transition`}>
                  <div className="flex items-center gap-3">
