/* Minimal base to complement provided utility rendering on platform */
:root { color-scheme: light dark; }
* { box-sizing: border-box; }
html, body, #root { height: 100%; }
body { margin: 0; line-height: 1.5; font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji"; }
img { display: block; max-width: 100%; }
button, input, select, textarea { font: inherit; }

/***** Utility helpers (very light), platform provides tailwind-like utilities *****/
.dark .dark\:bg-gray-800 { background-color: #1f2937; }
.dark .dark\:bg-gray-900 { background-color: #0f172a; }
.dark .dark\:text-gray-100 { color: #f3f4f6; }
.dark .dark\:text-blue-200 { color: #bfdbfe; }
.dark .dark\:hover\:bg-gray-700:hover { background-color: #374151; }
.dark .dark\:border-gray-700 { border-color: #374151; }
.dark .dark\:from-gray-800 { --tw-gradient-from: #1f2937; --tw-gradient-stops: var(--tw-gradient-from), var(--tw-gradient-to, rgba(31,41,55,0)); }
.dark .dark\:to-gray-900 { --tw-gradient-to: #0f172a; }

/***** Smooth scrolling for anchors *****/
html { scroll-behavior: smooth; }

