                <button className="px-4 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 transition dark:bg-gray-700 dark:hover:bg-gray-600 w-full">Sign in</button>
                <a href="#demo" className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition w-full text-center">Start</a>
              </div>
            </div>
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;

