async function getMock<T>(endpoint: string): Promise<T> {
  await delay(400);
  switch (endpoint) {
    case 'mock:ideas':
      return JSON.parse(JSON.stringify(ideasSeed)) as T;
    case 'mock:features':
      return JSON.parse(JSON.stringify(featuresSeed)) as T;
    case 'mock:testimonials':
      return JSON.parse(JSON.stringify(testimonialsSeed)) as T;
    default:
      throw new Error('Unknown mock endpoint: ' + endpoint);
  }
}

export default function useFetch<T = any>(endpoint: string) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetcher = async () => {
    try {
      setLoading(true);
      setError(null);
      if (endpoint.startsWith('mock:')) {
        const res = await getMock<T>(endpoint);
        setData(res);
      } else if (endpoint.startsWith('http')) {
        const res = await fetch(endpoint);
        if (!res.ok) throw new Error('Network error');
        const json = (await res.json()) as T;
        setData(json);
      } else {
        throw new Error('Invalid endpoint: ' + endpoint);
      }
    } catch (e: any) {
      setError(e?.message || 'Unknown error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetcher();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [endpoint]);

  return { data, loading, error, refetch: fetcher } as const;
}

